INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('all', 'op', 46, 'OP', '全部；所有', 'the whole number or amount', 'All the children came into the room.', '所有孩子都进了房间。', '[{"w":"the","def":"the: 相关的动作或关系词","vs":"与 all 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"the\" / \"all\" 的替换练习"},{"w":"any","def":"any: 可帮助扩展句型的基础词","vs":"与 all 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"any\" / \"all\" 的替换练习"},{"w":"every","def":"every: 同一组 Basic English 操作词","vs":"与 all 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"every\" / \"all\" 的替换练习"}]'),
  ('any', 'op', 47, 'OP', '任何；一些；无论哪一个', 'one, some, or every member of a group', 'Do you have any paper for this note?', '你有写这张便条用的纸吗？', '[{"w":"all","def":"all: 相关的动作或关系词","vs":"与 any 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"all\" / \"any\" 的替换练习"},{"w":"every","def":"every: 可帮助扩展句型的基础词","vs":"与 any 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"every\" / \"any\" 的替换练习"},{"w":"little","def":"little: 同一组 Basic English 操作词","vs":"与 any 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"little\" / \"any\" 的替换练习"}]'),
  ('every', 'op', 48, 'OP', '每一个；所有的', 'each member of a group without exception', 'Every student must read one page.', '每个学生都必须读一页。', '[{"w":"any","def":"any: 相关的动作或关系词","vs":"与 every 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"any\" / \"every\" 的替换练习"},{"w":"little","def":"little: 可帮助扩展句型的基础词","vs":"与 every 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"little\" / \"every\" 的替换练习"},{"w":"much","def":"much: 同一组 Basic English 操作词","vs":"与 every 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"much\" / \"every\" 的替换练习"}]'),
  ('little', 'op', 49, 'OP', '小的；少量的', 'small in size or amount', 'A little fire gave us enough heat.', '一小堆火给了我们足够的热量。', '[{"w":"every","def":"every: 相关的动作或关系词","vs":"与 little 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"every\" / \"little\" 的替换练习"},{"w":"much","def":"much: 可帮助扩展句型的基础词","vs":"与 little 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"much\" / \"little\" 的替换练习"},{"w":"no","def":"no: 同一组 Basic English 操作词","vs":"与 little 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"no\" / \"little\" 的替换练习"}]'),
  ('much', 'op', 50, 'OP', '许多；大量；很', 'a great amount or degree', 'There is much water in the river today.', '今天河里有很多水。', '[{"w":"little","def":"little: 相关的动作或关系词","vs":"与 much 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"little\" / \"much\" 的替换练习"},{"w":"no","def":"no: 可帮助扩展句型的基础词","vs":"与 much 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"no\" / \"much\" 的替换练习"},{"w":"other","def":"other: 同一组 Basic English 操作词","vs":"与 much 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"other\" / \"much\" 的替换练习"}]');
